1	import { useState } from "react";
2	import { useSession } from "@/features/session/context";
3	import { useMarketComments, usePostMarketComment } from "@/lib/query/hooks";
4	import { formatRelativeTime } from "@/lib/utils/format";
5	import type { Market } from "@/lib/api/types";
6	
7	const MAX_COMMENT_BODY_LENGTH = 2000;
8	
9	interface DiscussionThreadProps {
10	  market: Market;
11	}
12	
13	export function DiscussionThread({ market }: DiscussionThreadProps) {
14	  const { session, isConfigured } = useSession();
15	  const comments = useMarketComments(market.id);
16	  const mutation = usePostMarketComment(market.id);
17	  const [body, setBody] = useState("");
18	
19	  const trimmedBody = body.trim();
20	  const remaining = MAX_COMMENT_BODY_LENGTH - body.length;
21	  const isReadOnly = market.status !== "active";
22	
23	  const handleSubmit = (event: React.FormEvent<HTMLFormElement>) => {
24	    event.preventDefault();
25	    if (!isConfigured || isReadOnly || !trimmedBody) {
26	      return;
27	    }
28	
29	    mutation.mutate(
30	      {
31	        payload: {
32	          accountId: session.accountId,
33	          body: trimmedBody,
34	          idempotencyKey: crypto.randomUUID(),
35	        },
36	        session,
37	      },
38	      {
39	        onSuccess: () => {
40	          setBody("");
41	        },
42	      },
43	    );
44	  };
45	
46	  return (
47	    <section style={panelStyle}>
48	      <div style={headerStyle}>
49	        <div>
50	          <h2 style={titleStyle}>Discussion</h2>
51	          <p style={subtitleStyle}>Market commentary and participant notes.</p>
52	        </div>
53	        {comments.data && (
54	          <span style={countStyle}>
55	            {comments.data.pagination.returned} comment{comments.data.pagination.returned === 1 ? "" : "s"}
56	          </span>
57	        )}
